// frontend/assets/js/api_client.js
//
// =============================================================================
// vyraFetch helper (v3.34.0 + R016/R017 v3.34.1)
// -----------------------------------------------------------------------------
// Public alias: `window.vyraFetch(path, { method, body, auth, responseType, signal })`
//   - path:         string, API_BASE_URL'e relative ("/auth/login" gibi)
//   - method:       "GET" | "POST" | ... (default "GET")
//   - body:         JS object → JSON.stringify (default null)
//   - auth:         boolean — true ise Authorization: Bearer <access_token> ekler
//                   (default true). Login/register gibi public uçlar için false.
//   - responseType: "json" (default) | "stream" | "blob" (R016)
//                   - json:   parse edilmiş JS objesi döner.
//                   - stream: raw Response döner; caller body.getReader() ile SSE/
//                             streaming consume eder.
//                   - blob:   Response.blob() döner (download/preview).
//                   Auth + 4xx/5xx friendly-error kontratı 3 path'te de aynıdır.
//   - signal:       AbortController.signal — özellikle stream iptali için.
//
// Dönüş (default): parse edilmiş JSON objesi.
//   stream → Response, blob → Blob.
//
// Ayrıca: `window.vyraFetchUI(path, opts, { onSuccess, onError, loadingEl })`
//   R017 — try/catch + loading-state + error-display boilerplate'ini
//   absorbe eder. Mevcut vyraFetch çağrıları değişmez (additive).
//
// Hata kontratı (Türkçe — kullanıcıya doğrudan gösterilebilir):
//   - Ağ hatası (TypeError / "Failed to fetch") →
//       "Sunucuya bağlanılamadı. Proxy (Nginx) çalışmıyor olabilir
//        veya ağ bağlantınızı kontrol edin."
//   - 502/503/504 (proxy / backend down, HTML response) →
//       "Backend servisi yanıt vermiyor (HTTP {status}). Lütfen sistem yöneticinize bildirin."
//   - Diğer non-JSON 5xx →
//       "Sunucu hatası ({status}). Lütfen tekrar deneyin."
//   - Non-JSON 4xx →
//       "İstek reddedildi ({status})."
//   - 401 (JSON body yoksa veya detail boşsa) →
//       "Oturum sona erdi. Lütfen yeniden giriş yapın."
//   - 403 (JSON body yoksa veya detail boşsa) →
//       "Bu işlem için yetkiniz yok."
//   - JSON body varsa: data.detail veya data.message tercih edilir.
//
// Thrown Error nesnesi şu propertyleri taşır:
//   .message  — Türkçe friendly mesaj
//   .status   — HTTP status code (network failure'da undefined)
//   .data     — parse edilmiş response body (varsa) veya { raw: text }
//
// Geriye dönük uyumluluk: `window.VYRA_API.request(...)` aynı imzayı korur,
// başka modüller (query_builder.js vb.) bu çağrı yolunu kullanmaya devam eder.
// =============================================================================

(function () {
    console.log("[NGSSAI] api_client.js loaded");

    // Backend URL (FastAPI) - Port 8002
    const API_BASE_URL = (window.API_BASE_URL || "http://localhost:8002") + "/api";

    function getTokens() {
        return {
            access: localStorage.getItem("access_token"),
            refresh: localStorage.getItem("refresh_token"),
        };
    }

    function setTokens(access, refresh) {
        if (access) localStorage.setItem("access_token", access);
        if (refresh) localStorage.setItem("refresh_token", refresh);
    }

    // ---- Friendly Turkish error builder ----
    function buildFriendlyMessage(status, isJson, data) {
        // 401 fast path
        if (status === 401) {
            const detail = data && (data.detail || data.message);
            return detail || "Oturum sona erdi. Lütfen yeniden giriş yapın.";
        }
        // 403 fast path
        if (status === 403) {
            const detail = data && (data.detail || data.message);
            return detail || "Bu işlem için yetkiniz yok.";
        }
        // JSON-formatlı hata: backend mesajını kullan
        if (isJson && data && (data.detail || data.message)) {
            return data.detail || data.message;
        }
        // 502/503/504 — proxy/backend down (genellikle HTML body)
        if (status === 502 || status === 503 || status === 504) {
            return `Backend servisi yanıt vermiyor (HTTP ${status}). Lütfen sistem yöneticinize bildirin.`;
        }
        // Diğer 5xx (non-JSON)
        if (status >= 500 && status < 600) {
            return `Sunucu hatası (${status}). Lütfen tekrar deneyin.`;
        }
        // Non-JSON 4xx
        if (status >= 400 && status < 500) {
            return `İstek reddedildi (${status}).`;
        }
        // Fallback
        return `API error (${status})`;
    }

    // R016 (v3.34.1): non-2xx Response'tan friendly error fırlatma helper'ı —
    // hem JSON hem stream/blob yolu tarafından paylaşılır (DRY).
    async function _throwFriendlyHttpError(res) {
        let raw = "";
        try { raw = await res.text(); } catch { /* body okunamadı */ }
        let data = null;
        let parsedAsJson = false;
        if (raw) {
            try { data = JSON.parse(raw); parsedAsJson = true; }
            catch { data = { raw }; }
        }
        const msg = buildFriendlyMessage(res.status, parsedAsJson, parsedAsJson ? data : null);
        const err = new Error(msg);
        err.status = res.status;
        err.data = data;
        console.error("[NGSSAI] API error:", err);
        throw err;
    }

    /**
     * Core fetch helper.
     *
     * Opts:
     *   - method, body, auth — bkz. dosya başı dokümantasyonu.
     *   - responseType (R016, v3.34.1):
     *       'json'   (default) — parsed JSON object (geriye dönük uyum).
     *       'stream' — raw Response döner; caller `res.body.getReader()` ile
     *                  SSE/streaming consume eder. Auth header + non-2xx
     *                  friendly error halen uygulanır.
     *       'blob'   — `Response.blob()` döner; caller download/preview
     *                  yapar. Auth header + non-2xx friendly error halen
     *                  uygulanır.
     *   - signal (R016) — AbortController.signal; stream iptali için pratiktir.
     */
    async function request(path, {
        method = "GET",
        body = null,
        auth = true,
        responseType = "json",
        signal = undefined,
    } = {}) {
        const url = `${API_BASE_URL}${path}`;
        const headers = {
            "Content-Type": "application/json",
        };

        if (auth) {
            const { access } = getTokens();
            if (access) {
                headers["Authorization"] = `Bearer ${access}`;
            }
        }

        console.log("[NGSSAI] API request:", method, url, responseType !== "json" ? `(${responseType})` : "");

        // ---- Outer fetch try/catch: ağ hatasını yakala ----
        let res;
        try {
            res = await fetch(url, {
                method,
                headers,
                credentials: 'include',
                body: body ? JSON.stringify(body) : null,
                signal,
            });
        } catch (netErr) {
            // AbortError'ı friendly-wrap etmiyoruz — caller intent'i (signal.abort) bilinçli.
            if (netErr && netErr.name === "AbortError") {
                throw netErr;
            }
            // TypeError = network failure / "Failed to fetch" (Nginx down, DNS, vb.)
            const friendly = "Sunucuya bağlanılamadı. Proxy (Nginx) çalışmıyor olabilir veya ağ bağlantınızı kontrol edin.";
            const err = new Error(friendly);
            err.status = undefined;
            err.data = null;
            err.cause = netErr;
            console.error("[NGSSAI] API network error:", netErr);
            throw err;
        }

        // R016: stream / blob path — JSON parse atla, ham Response'u döndür.
        if (responseType === "stream") {
            if (!res.ok) {
                await _throwFriendlyHttpError(res);
            }
            return res;  // caller: res.body.getReader() / EventSource pattern
        }

        if (responseType === "blob") {
            if (!res.ok) {
                await _throwFriendlyHttpError(res);
            }
            return await res.blob();
        }

        // Default: JSON path (geriye dönük davranış).
        const text = await res.text();
        const contentType = (res.headers.get("content-type") || "").toLowerCase();
        const looksJson = contentType.includes("application/json");

        let data = null;
        let parsedAsJson = false;
        try {
            if (text) {
                data = JSON.parse(text);
                parsedAsJson = true;
            }
        } catch {
            // Parse başarısız — HTML/text response (Nginx 502 vb.)
            data = { raw: text };
            parsedAsJson = false;
        }

        if (!res.ok) {
            const isJson = parsedAsJson && looksJson !== false;
            const msg = buildFriendlyMessage(res.status, parsedAsJson, parsedAsJson ? data : null);
            const err = new Error(msg);
            err.status = res.status;
            err.data = data;
            console.error("[NGSSAI] API error:", err);
            throw err;
        }

        return data;
    }

    /**
     * Login helper.
     *
     * v3.34.0: Yeni imza — opts objesi (gerçek backend kontratı):
     *   login({ username, password, domain })  → POST /auth/login
     *
     * Eski imza (geri uyum için korunur — DEPRECATED):
     *   login(phone, password)  → POST /auth/login { phone, password }
     *   Bu imza eski telefon-tabanlı login için kullanılıyordu. Yeni kod
     *   `{username, password, domain}` formunu kullanmalıdır.
     */
    async function login(phoneOrOpts, maybePassword) {
        let body;
        if (typeof phoneOrOpts === "string") {
            // Legacy path — DEPRECATED
            console.warn("[VYRA_API] login(phone, password) DEPRECATED — use login({username, password, domain})");
            body = { phone: phoneOrOpts, password: maybePassword };
        } else {
            // Modern path — { username, password, domain }
            body = phoneOrOpts || {};
        }
        const data = await request("/auth/login", {
            method: "POST",
            body,
            auth: false,
        });
        setTokens(data.access_token, data.refresh_token);
        return data;
    }

    async function registerUser(full_name, phone, password, role = "user") {
        const data = await request("/auth/register", {
            method: "POST",
            body: { full_name, phone, password, role },
            auth: false,
        });
        return data;
    }

    async function refreshToken() {
        const { refresh } = getTokens();
        if (!refresh) return null;

        const data = await request("/auth/refresh", {
            method: "POST",
            body: { refresh_token: refresh },
            auth: false,
        });

        setTokens(data.access_token, data.refresh_token || refresh);
        return data;
    }

    window.VYRA_API = {
        request,
        login,
        registerUser,
        refreshToken,
        getTokens,
        setTokens,
    };

    // v3.34.0: Public defensive fetch alias.
    // Tek satırlık delegasyon — VYRA_API.request'in tüm error contract'ını miras alır.
    // Yeni modüller doğrudan window.vyraFetch(...) çağırmalı; legacy modüller
    // VYRA_API.request'i kullanmaya devam edebilir (her ikisi de aynı kod yolu).
    window.vyraFetch = function (path, opts) {
        return window.VYRA_API.request(path, opts);
    };

    // R017 (v3.34.1): UI-aware vyraFetch wrapper.
    // ----------------------------------------------------------------
    // Mevcut 28 modülde tekrar eden boilerplate:
    //
    //     try {
    //         const data = await vyraFetch(path, opts);
    //         render(data);
    //     } catch (err) {
    //         showError(root, "Yükleme hatası: " + err.message);
    //     }
    //
    // vyraFetchUI bunu absorbe eder:
    //
    //     await vyraFetchUI(path, opts, {
    //         onSuccess: data => render(data),
    //         onError:   err  => showError(root, err.message),
    //         loadingEl: btn,            // optional — disabled toggle
    //     });
    //
    // Opts ikinci argüman vyraFetch'inkiyle birebir aynı (method/body/auth/
    // responseType/signal). Wrapper hiçbir varsayılan değiştirmez.
    //
    // ui-opts (üçüncü argüman):
    //   - onSuccess(data)        — başarı (4xx/5xx atılmadıysa) callback.
    //   - onError(err)           — vyraFetch friendly Error yakalandığında.
    //                              Verilmezse hata RE-THROW edilir (caller
    //                              kendi try/catch'inde yakalar).
    //   - loadingEl              — opsiyonel DOM element; çağrı başında
    //                              `disabled=true` + `aria-busy="true"`,
    //                              sonunda restore.
    //
    // Dönüş: vyraFetch çıktısı (data) veya onError'dan dönen değer (varsa).
    //
    // Geriye dönük uyum: vyraFetch çağrıları HİÇ etkilenmez; bu helper
    // saf opt-in additive. Mevcut 28 modül adoption için ayrı PR (R020).
    window.vyraFetchUI = async function (path, opts, uiOpts) {
        const { onSuccess, onError, loadingEl } = uiOpts || {};

        // Loading-state on
        let prevDisabled, prevAriaBusy;
        if (loadingEl) {
            prevDisabled = loadingEl.disabled;
            prevAriaBusy = loadingEl.getAttribute("aria-busy");
            loadingEl.disabled = true;
            loadingEl.setAttribute("aria-busy", "true");
        }

        try {
            const data = await window.vyraFetch(path, opts);
            if (typeof onSuccess === "function") {
                try { onSuccess(data); }
                catch (cbErr) {
                    console.error("[vyraFetchUI] onSuccess callback threw:", cbErr);
                }
            }
            return data;
        } catch (err) {
            if (typeof onError === "function") {
                try { return onError(err); }
                catch (cbErr) {
                    console.error("[vyraFetchUI] onError callback threw:", cbErr);
                    throw err;  // orijinal hata baskın
                }
            } else {
                throw err;
            }
        } finally {
            // Loading-state off
            if (loadingEl) {
                loadingEl.disabled = prevDisabled || false;
                if (prevAriaBusy === null) {
                    loadingEl.removeAttribute("aria-busy");
                } else {
                    loadingEl.setAttribute("aria-busy", prevAriaBusy);
                }
            }
        }
    };

    // v3.32.0: Canonical Authorization header helper.
    // query_builder.js (ve diğer bundle modülleri) `window.getAuthHeader()` bekliyor;
    // daha önce hiçbir modül tanımlamıyordu → /api/query-state/preview gibi auth'lu
    // çağrılar header'sız gidip 401 dönüyordu. api_client.js bundle'da olduğu için
    // home.html'de bu helper artık her zaman tanımlı.
    if (!window.getAuthHeader) {
        window.getAuthHeader = function () {
            const { access } = getTokens();
            return access ? { Authorization: 'Bearer ' + access } : {};
        };
    }
})();


/* === assets/js/websocket_client.js === */
/**
 * NGSSAI - WebSocket Client Module
 * ==========================================
 * Asenkron işlem sonuçları için WebSocket bağlantı yönetimi.
 */

(function () {
    'use strict';

    // --- CONFIGURATION ---
    const WS_BASE_URL = window.WS_BASE_URL || 'ws://localhost:8002/api/ws';
    const RECONNECT_DELAY_MS = 3000;
    const MAX_RECONNECT_ATTEMPTS = 5;
    const HEARTBEAT_INTERVAL_MS = 30000;

    // --- STATE ---
    let socket = null;
    let reconnectAttempts = 0;
    let heartbeatTimer = null;
    let isConnecting = false;
    let pendingTasks = new Map(); // task_id -> callback

    // --- CORE FUNCTIONS ---

    function getToken() {
        return localStorage.getItem('access_token');
    }

    function connect() {
        if (isConnecting || (socket && socket.readyState === WebSocket.OPEN)) {
            console.log('[NGSSAI-WS] Zaten bağlı veya bağlanıyor...');
            return;
        }

        const token = getToken();
        if (!token) {
            console.warn('[NGSSAI-WS] Token yok, WebSocket bağlantısı yapılamaz');
            return;
        }

        isConnecting = true;
        const wsUrl = `${WS_BASE_URL}?token=${encodeURIComponent(token)}`;

        console.log('[NGSSAI-WS] Bağlanıyor...');

        try {
            socket = new WebSocket(wsUrl);

            socket.onopen = function () {
                console.log('[NGSSAI-WS] ✅ Bağlantı kuruldu');
                isConnecting = false;
                reconnectAttempts = 0;
                startHeartbeat();

                // UI durum güncelle
                updateConnectionStatus(true);

                // Bekleyen görevleri sorgula
                requestPendingTasks();
            };

            socket.onmessage = function (event) {
                try {
                    const data = JSON.parse(event.data);
                    handleMessage(data);
                } catch (err) {
                    console.error('[NGSSAI-WS] Mesaj parse hatası:', err);
                }
            };

            socket.onclose = function (event) {
                console.log('[NGSSAI-WS] Bağlantı kapandı:', event.code, event.reason);
                isConnecting = false;
                stopHeartbeat();
                updateConnectionStatus(false);
                scheduleReconnect();
            };

            socket.onerror = function (error) {
                console.error('[NGSSAI-WS] Hata:', error);
                isConnecting = false;
            };

        } catch (err) {
            console.error('[NGSSAI-WS] Bağlantı hatası:', err);
            isConnecting = false;
            scheduleReconnect();
        }
    }

    function disconnect() {
        stopHeartbeat();
        if (socket) {
            socket.close();
            socket = null;
        }
        reconnectAttempts = 0;
    }

    function scheduleReconnect() {
        if (reconnectAttempts >= MAX_RECONNECT_ATTEMPTS) {
            // v3.14.6: Spam'i azalt — sessizce vazgeç, sonraki sayfa etkileşiminde tekrar dene
            console.warn('[NGSSAI-WS] Bağlantı kurulamadı, WS özellikleri devre dışı (sayfa yenilenince tekrar denenir).');
            return;
        }

        reconnectAttempts++;
        // v3.14.6: Üstel backoff yerine sabit + cap (max 30s); ilk deneme hemen
        const delay = Math.min(RECONNECT_DELAY_MS * reconnectAttempts, 30000);
        // Sadece ilk 2 denemeyi göster, gerisi info seviyesinde
        if (reconnectAttempts <= 2) {
            console.log(`[NGSSAI-WS] ${delay}ms sonra yeniden bağlanılacak (deneme ${reconnectAttempts}/${MAX_RECONNECT_ATTEMPTS})`);
        }

        setTimeout(() => {
            if (!socket || socket.readyState === WebSocket.CLOSED) {
                connect();
            }
        }, delay);
    }

    function startHeartbeat() {
        stopHeartbeat();
        heartbeatTimer = setInterval(() => {
            if (socket && socket.readyState === WebSocket.OPEN) {
                socket.send(JSON.stringify({ type: 'ping' }));
            }
        }, HEARTBEAT_INTERVAL_MS);
    }

    function stopHeartbeat() {
        if (heartbeatTimer) {
            clearInterval(heartbeatTimer);
            heartbeatTimer = null;
        }
    }

    function updateConnectionStatus(isConnected) {
        const statusEl = document.getElementById('wsConnectionStatus');
        if (!statusEl) return;

        const dotEl = statusEl.querySelector('.status-dot');
        const textEl = statusEl.querySelector('.status-text');

        if (isConnected) {
            statusEl.classList.remove('offline');
            statusEl.classList.add('online');
            if (dotEl) dotEl.style.background = '#10b981';
            if (textEl) textEl.textContent = 'Çevrimiçi';
        } else {
            statusEl.classList.remove('online');
            statusEl.classList.add('offline');
            if (dotEl) dotEl.style.background = '#ef4444';
            if (textEl) textEl.textContent = 'Çevrimdışı';
        }
    }

    function send(message) {
        if (socket && socket.readyState === WebSocket.OPEN) {
            socket.send(JSON.stringify(message));
            return true;
        }
        console.warn('[NGSSAI-WS] Mesaj gönderilemedi, bağlantı yok');
        return false;
    }

    function requestPendingTasks() {
        send({ type: 'get_pending_tasks' });
    }

    // --- MESSAGE HANDLERS ---

    function handleMessage(data) {
        console.log('[NGSSAI-WS] Mesaj alındı:', data.type);

        switch (data.type) {
            case 'connected':
                console.log('[NGSSAI-WS] Sunucu bağlantı onayı:', data.message);
                break;

            case 'pong':
                // Heartbeat yanıtı, sessizce geç
                break;

            case 'task_complete':
                handleTaskComplete(data);
                break;

            case 'task_failed':
                handleTaskFailed(data);
                break;

            case 'task_status':
                handleTaskStatus(data);
                break;

            case 'pending_tasks':
                handlePendingTasks(data);
                break;

            // === DIALOG MESAJ TİPLERİ (v2.15.0) ===
            case 'dialog_message':
                handleDialogMessage(data);
                break;

            case 'dialog_typing':
                handleDialogTyping(data);
                break;

            // === v3.14.0: Asenkron DB Sorgu Tamamlandı ===
            case 'db_query_complete':
                handleDbQueryComplete(data);
                break;

            // === RAG UPLOAD BİLDİRİMLERİ (v2.39.0) ===
            case 'rag_upload_progress':
                handleRagUploadProgress(data);
                break;

            case 'rag_upload_complete':
                handleRagUploadComplete(data);
                break;

            case 'rag_upload_failed':
                handleRagUploadFailed(data);
                break;

            // === ENHANCEMENT PROGRESS (v3.3.0) ===
            case 'enhancement_progress':
                handleEnhancementProgress(data);
                break;

            case 'error':
                console.error('[NGSSAI-WS] Sunucu hatası:', data.message);
                break;

            default:
                console.log('[NGSSAI-WS] Bilinmeyen mesaj tipi:', data.type);
        }
    }

    function handleTaskComplete(data) {
        const { task_id, result } = data;
        console.log('[NGSSAI-WS] ✅ Görev tamamlandı:', task_id);

        // Callback varsa çağır
        const callback = pendingTasks.get(task_id);
        if (callback) {
            callback(null, result);
            pendingTasks.delete(task_id);
        }

        // Global event dispatch
        window.dispatchEvent(new CustomEvent('vyra:task_complete', {
            detail: { task_id, result }
        }));

        // Toast bildirimi
        if (typeof VyraToast !== 'undefined') {
            VyraToast.success('Çözüm önerisi hazır!');
        }

        // 🔔 Browser notification (kullanıcı başka sekmede/browserdayse)
        showTicketNotification(result);

        // Sonucu göster
        showSolutionResult(result);
    }

    /**
     * v2.24.0: NGSSAI'ye Sor için browser notification göster
     * Tıklandığında dialog sekmesine yönlendirir
     */
    function showTicketNotification(result) {
        const title = '✅ Çözüm Önerisi Hazır!';
        const body = result?.final_solution?.substring(0, 100) || 'Çözüm öneriniz hazırlandı';

        // 1️⃣ Her durumda NgssNotification ile in-app bildirim göster
        if (typeof NgssNotification !== 'undefined') {
            NgssNotification.add('success', title, body);
        }

        // 2️⃣ Sayfa gizliyse browser notification da göster
        if (document.hidden && 'Notification' in window && Notification.permission === 'granted') {
            const notification = new Notification(title, {
                body: body,
                icon: '/assets/images/vyra_logo.png',
                tag: 'vyra-ticket-response',
                requireInteraction: true
            });

            notification.onclick = () => {
                // Pencereyi öne getir
                window.focus();

                // v2.24.0: NGSSAI'ye Sor (Dialog) sekmesine git
                const dialogTab = document.getElementById('tabDialog');
                if (dialogTab) {
                    dialogTab.click();
                }

                notification.close();
            };

            // 10 saniye sonra otomatik kapat
            setTimeout(() => notification.close(), 10000);
        }
    }

    function handleTaskFailed(data) {
        const { task_id, error } = data;
        console.error('[NGSSAI-WS] ❌ Görev başarısız:', task_id, error);

        // Callback varsa çağır
        const callback = pendingTasks.get(task_id);
        if (callback) {
            callback(error, null);
            pendingTasks.delete(task_id);
        }

        // Global event dispatch
        window.dispatchEvent(new CustomEvent('vyra:task_failed', {
            detail: { task_id, error }
        }));

        // 🌐 VPN/Network hatası kontrolü
        if (window.isVPNNetworkError && window.isVPNNetworkError(error)) {
            window.showVPNErrorPopup();
        } else if (typeof VyraToast !== 'undefined') {
            VyraToast.error('Çözüm hazırlanamadı: ' + (error || 'Bilinmeyen hata'));
        }
    }

    function handleTaskStatus(data) {
        console.log('[NGSSAI-WS] Görev durumu:', data.task_id, data.status);
    }

    function handlePendingTasks(data) {
        const tasks = data.tasks || [];
        console.log('[NGSSAI-WS] Bekleyen görevler:', tasks.length);

        // Bekleyen görev varsa bildir
        if (tasks.length > 0) {
            tasks.forEach(task => {
                if (typeof VyraToast !== 'undefined') {
                    VyraToast.info(`Bekleyen görev: ${task.progress_message}`);
                }
            });
        }
    }

    // === DIALOG MESSAGE HANDLERS (v2.15.0) ===

    function handleDialogMessage(data) {
        const message = data.message;
        const quickReply = data.quick_reply;
        const dialogId = data.dialog_id;

        console.log('[NGSSAI-WS] 💬 Dialog mesajı alındı:', dialogId);

        // Duplicate önleme: Eğer DialogChatModule HTTP response bekliyorsa, mesajı ekleme
        // (HTTP response zaten ekleyecek)
        const isWaiting = window.DialogChatModule?.isWaitingForResponse?.();
        if (isWaiting) {
            console.log('[NGSSAI-WS] HTTP response bekleniyor, WebSocket mesajı atlanıyor (duplicate önleme)');
            // Ama notification ekle (kullanıcı başka sekmede olabilir)
        } else {
            // DialogChatModule varsa mesajı ekle
            if (window.DialogChatModule && typeof DialogChatModule.addMessageFromWS === 'function') {
                DialogChatModule.addMessageFromWS(message, quickReply);
            }
        }

        // Notification Center'a bildirim ekle (tıklayınca dialog sekmesine gider)
        if (typeof NgssNotification !== 'undefined') {
            const msgPreview = message?.content?.substring(0, 80) || 'Yeni yanıt hazır';
            // v2.24.6: dialogId parametresi eklendi
            NgssNotification.add('success', '🤖 ' + (window.BrandingEngine ? BrandingEngine.getAppName() : 'VYRA') + ' Yanıtladı', msgPreview, dialogId);
        }

        // Browser notification göster (kullanıcı başka sekmede/browserdayse)
        if (document.hidden) {
            showDialogNotification(message);
        }

        // Global event dispatch
        window.dispatchEvent(new CustomEvent('vyra:dialog_message', {
            detail: { dialog_id: dialogId, message, quick_reply: quickReply }
        }));
    }

    // === v3.14.0: Asenkron DB Sorgu Tamamlandı Handler ===
    function handleDbQueryComplete(data) {
        const { dialog_id: dialogId, job_id: jobId, query_text_short: shortQ,
                result_summary: summary, message_id: msgId, message } = data;

        console.log('[NGSSAI-WS] 📊 DB sorgu tamamlandı:', shortQ, '→', summary);

        // 1. Chat'te placeholder kartı güncelle (kullanıcı hala aynı sayfadaysa)
        const statusEl = document.getElementById(`dbqs_${jobId}`);
        if (statusEl) {
            statusEl.textContent = `✅ ${summary}`;
            statusEl.classList.add('db-query-done');
        }

        // 2. Mesajı dialog'a ekle (SSE ile zaten eklenmediyse)
        if (msgId) {
            const existing = document.querySelector(`[data-message-id="${msgId}"]`);
            if (!existing && window.DialogChatModule && typeof DialogChatModule.addMessageFromWS === 'function') {
                DialogChatModule.addMessageFromWS(message);
            }
        }

        // 3. Bildirim — soru bazlı, tıklayınca ilgili mesaja gider
        if (typeof NgssNotification !== 'undefined') {
            const appName = window.BrandingEngine ? BrandingEngine.getAppName() : 'VYRA';
            NgssNotification.add(
                'success',
                `📊 ${shortQ}`,
                `✅ ${summary}`,
                dialogId
            );
        }

        // 4. Browser notification (sayfa gizliyse)
        if (document.hidden && 'Notification' in window && Notification.permission === 'granted') {
            try {
                const notif = new Notification(`📊 ${shortQ}`, {
                    body: `✅ ${summary}`,
                    icon: '/assets/images/vyra_logo.png',
                    tag: `db-query-${jobId}`,
                });
                notif.onclick = () => {
                    window.focus();
                    if (typeof NgssNotification !== 'undefined') {
                        NgssNotification.navigateToDialog(dialogId);
                    }
                };
            } catch (e) { /* Browser notification hatası */ }
        }

        // 5. Global event
        window.dispatchEvent(new CustomEvent('vyra:db_query_complete', {
            detail: { dialog_id: dialogId, job_id: jobId, summary, message_id: msgId }
        }));
    }

    function handleDialogTyping(data) {
        const isTyping = data.is_typing;

        // DialogChatModule varsa typing indicator göster/gizle
        if (window.DialogChatModule) {
            if (isTyping && typeof DialogChatModule.showTypingIndicator === 'function') {
                DialogChatModule.showTypingIndicator();
            } else if (!isTyping && typeof DialogChatModule.hideTypingIndicator === 'function') {
                DialogChatModule.hideTypingIndicator();
            }
        }
    }

    function showDialogNotification(message) {
        // Browser notification izni kontrolü
        if (!('Notification' in window) || Notification.permission !== 'granted') {
            return;
        }

        const title = '🤖 ' + (window.BrandingEngine ? BrandingEngine.getAppName() : 'VYRA') + ' Yanıtladı';
        const body = message?.content?.substring(0, 100) || 'Yeni yanıt hazır';

        const notification = new Notification(title, {
            body: body,
            icon: '/assets/images/vyra_logo.png',
            tag: 'vyra-dialog-response',
            requireInteraction: true
        });

        notification.onclick = () => {
            // Pencereyi öne getir
            window.focus();

            // NGSSAI'ye Sor sekmesine git
            const dialogTab = document.getElementById('tabDialog');
            if (dialogTab) {
                dialogTab.click();
            }

            notification.close();
        };

        // 10 saniye sonra otomatik kapat
        setTimeout(() => notification.close(), 10000);
    }

    // === RAG UPLOAD HANDLERS (v2.39.0) ===

    /**
     * Dosya bazlı ilerleme bildirimi handler'ı
     */
    function handleRagUploadProgress(data) {
        const { current, total, file_name, percentage, message } = data;
        console.log(`[NGSSAI-WS] 📄 RAG upload ilerleme: ${current}/${total} (${percentage}%)`);

        // Toast ile ilerleme göster (sadece çoklu dosyada göster)
        if (total > 1 && typeof VyraToast !== 'undefined') {
            VyraToast.info(`${message}`, 2000);
        }

        // Global event dispatch — RAG upload sayfası progress bar'ı güncelleyebilir
        window.dispatchEvent(new CustomEvent('vyra:rag_upload_progress', {
            detail: { current, total, file_name, percentage }
        }));
    }

    /**
     * v2.39.0: RAG dosya yükleme tamamlandı bildirimi
     * WebSocket üzerinden gelen mesajı işler.
     */
    function handleRagUploadComplete(data) {
        const fileNames = data.file_names || [];
        const processedCount = data.processed_count || 0;
        const totalChunks = data.total_chunks || 0;
        const failedFiles = data.failed_files || [];

        console.log('[NGSSAI-WS] 📄 RAG upload tamamlandı:', processedCount, 'dosya,', totalChunks, 'chunk');

        // Dosya isimleri özeti
        const fileList = fileNames.length <= 3
            ? fileNames.join(', ')
            : `${fileNames.slice(0, 2).join(', ')} ve ${fileNames.length - 2} dosya daha`;

        // Kısmi hata varsa uyarı, yoksa başarı
        const hasWarning = failedFiles.length > 0;
        const title = hasWarning ? '⚠️ Dosya Yükleme Kısmi Başarı' : '📄 Dosya Yüklendi';
        const body = hasWarning
            ? `${processedCount}/${fileNames.length} dosya işlendi. Hata: ${failedFiles.join(', ')}`
            : `Bilgi tabanına eklendi: ${fileList} (${totalChunks} chunk)`;
        const notifType = hasWarning ? 'warning' : 'success';

        // 0️⃣ v3.3.1: Processing polling'i durdur — WS'ten bildirim geldiği için
        if (window.RAGUpload && RAGUpload._processingPollTimer) {
            clearInterval(RAGUpload._processingPollTimer);
            RAGUpload._processingPollTimer = null;
            console.log('[NGSSAI-WS] Processing polling durduruldu (WS bildirimi geldi)');
        }

        // 1️⃣ NgssNotification ile in-app bildirim (tıklanınca Bilgi Tabanı sekmesine gider)
        if (typeof NgssNotification !== 'undefined') {
            NgssNotification.add(notifType, title, body, null, 'rag');
        }

        // 2️⃣ Dosya listesini yenile (kullanıcı RAG ekranındaysa)
        if (window.RAGUpload && typeof RAGUpload.loadFiles === 'function') {
            RAGUpload.filesCurrentPage = 1;
            RAGUpload.loadFiles();
            RAGUpload.loadStats();
            console.log('[NGSSAI-WS] RAG dosya listesi yenilendi');
        }

        // 3️⃣ Browser notification (kullanıcı başka sekmede/browserdayse)
        if (document.hidden && 'Notification' in window && Notification.permission === 'granted') {
            const notification = new Notification(title, {
                body: body,
                icon: '/assets/images/vyra_logo.png',
                tag: 'vyra-rag-upload',
                requireInteraction: false
            });

            notification.onclick = () => {
                window.focus();
                // Bilgi Tabanı sekmesine git
                if (typeof NgssNotification !== 'undefined') {
                    NgssNotification.navigateToRag();
                }
                notification.close();
            };

            setTimeout(() => notification.close(), 10000);
        }

        // 4️⃣ Global event dispatch
        window.dispatchEvent(new CustomEvent('vyra:rag_upload_complete', {
            detail: { file_names: fileNames, processed_count: processedCount, total_chunks: totalChunks }
        }));
    }

    /**
     * v2.39.0: RAG dosya yükleme başarısız bildirimi
     */
    function handleRagUploadFailed(data) {
        const fileNames = data.file_names || [];
        const failedFiles = data.failed_files || fileNames;
        const message = data.message || 'Dosya işleme hatası';

        console.error('[NGSSAI-WS] ❌ RAG upload başarısız:', failedFiles);

        // NgssNotification ile hata bildirimi
        if (typeof NgssNotification !== 'undefined') {
            NgssNotification.add('error', '❌ Dosya İşleme Hatası', message, null, 'rag');
        }

        // Dosya listesini yenile (failed durumunu görmek için)
        if (window.RAGUpload && typeof RAGUpload.loadFiles === 'function') {
            RAGUpload.loadFiles();
        }

        // Global event dispatch
        window.dispatchEvent(new CustomEvent('vyra:rag_upload_failed', {
            detail: { file_names: fileNames, failed_files: failedFiles, message }
        }));
    }

    // === ENHANCEMENT PROGRESS HANDLER (v3.3.0) ===

    /**
     * v3.3.0 [C5]: Enhancement progress bildirimi handler'ı
     * Doküman iyileştirme sırasında bölüm bazlı ilerleme gösterir.
     */
    function handleEnhancementProgress(data) {
        const { current, total, heading, status, percentage, message } = data;
        console.log(`[NGSSAI-WS] 📝 Enhancement progress: ${current}/${total} (${percentage}%) - ${status}`);

        // Global event dispatch — DocumentEnhancerModal dinleyecek
        window.dispatchEvent(new CustomEvent('vyra:enhancement_progress', {
            detail: { current, total, heading, status, percentage, message }
        }));
    }

    // --- UI HELPERS ---

    function showSolutionResult(result) {
        if (!result) return;

        const loadingBox = document.getElementById('loadingBox');
        const finalSolutionBox = document.getElementById('finalSolutionBox');

        // Loading'i gizle
        if (loadingBox) {
            loadingBox.classList.add('hidden');
        }

        // 🆕 v2.23.0: Artık RAG sonuçları + ticket_id döner
        // SolutionDisplayModule ile göster
        if (typeof window.SolutionDisplayModule !== 'undefined') {
            // ticket_id'yi sakla (AI değerlendirme için)
            window.currentTicketId = result.ticket_id;
            window.currentRagResults = result.rag_results || [];

            // RAG sonuçlarını göster
            window.SolutionDisplayModule.showRagResults(result);
        } else {
            // Fallback - eski davranış (basit gösterim)
            if (finalSolutionBox) {
                finalSolutionBox.classList.remove('hidden');
            }
            const solutionSteps = document.getElementById('solutionSteps');
            if (solutionSteps) {
                if (result.rag_results && result.rag_results.length > 0) {
                    solutionSteps.innerHTML = `<p class="text-yellow-400">🔍 ${result.rag_results.length} sonuç bulundu. Corpix ile değerlendirmek için butona tıklayın.</p>`;
                } else {
                    solutionSteps.innerHTML = `<p class="text-gray-400">Bilgi tabanında sonuç bulunamadı. Corpix ile değerlendirmek için butona tıklayın.</p>`;
                }
            }
        }

        // Ticket history'yi yenile
        if (typeof loadTicketHistory === 'function') {
            loadTicketHistory(true);
        }
    }

    // Fallback formatSolution - SolutionDisplayModule yoksa basit format
    function formatSolution(solution) {
        if (!solution) return '<p class="text-gray-500">Çözüm bilgisi yok</p>';
        // Basit fallback - modül yüklüyse zaten yukarıda kullanılıyor
        return `<p class="solution-text">${solution}</p>`;
    }

    // --- PUBLIC API ---

    /**
     * Asenkron ticket oluşturma isteği gönder
     */
    async function createTicketAsync(query, onComplete) {
        const token = getToken();
        if (!token) {
            throw new Error('Token bulunamadı');
        }

        // Loading göster
        const loadingBox = document.getElementById('loadingBox');
        const finalSolutionBox = document.getElementById('finalSolutionBox');

        if (loadingBox) loadingBox.classList.remove('hidden');
        if (finalSolutionBox) finalSolutionBox.classList.add('hidden');

        try {
            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            const data = await window.vyraFetch('/tickets/from-chat-async', {
                method: 'POST',
                body: { query }
            });
            console.log('[NGSSAI-WS] Görev oluşturuldu:', data.task_id);

            // Callback'i kaydet
            if (onComplete) {
                pendingTasks.set(data.task_id, onComplete);
            }

            // Toast bildirimi
            if (typeof VyraToast !== 'undefined') {
                VyraToast.info('Çözüm önerisi hazırlanıyor...');
            }

            return data;

        } catch (err) {
            console.error('[NGSSAI-WS] Async ticket hatası:', err);
            if (loadingBox) loadingBox.classList.add('hidden');
            throw err;
        }
    }

    /**
     * RAG araması yap (LLM kullanmadan)
     * Seçenek A: NGSSAI'ye Sor gibi hızlı arama
     */
    async function searchRAG(query) {
        const token = getToken();
        if (!token) {
            throw new Error('Token bulunamadı');
        }

        // Loading göster
        const loadingBox = document.getElementById('loadingBox');
        const finalSolutionBox = document.getElementById('finalSolutionBox');
        const ragSelectionBox = document.getElementById('ragSelectionBox');

        if (loadingBox) loadingBox.classList.remove('hidden');
        if (finalSolutionBox) finalSolutionBox.classList.add('hidden');
        if (ragSelectionBox) ragSelectionBox.classList.add('hidden');

        try {
            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            const data = await window.vyraFetch('/tickets/search', {
                method: 'POST',
                body: { query }
            });
            console.log('[NGSSAI-WS] RAG araması tamamlandı:', data.results?.length, 'sonuç');

            if (loadingBox) loadingBox.classList.add('hidden');

            return data;

        } catch (err) {
            console.error('[NGSSAI-WS] RAG arama hatası:', err);
            if (loadingBox) loadingBox.classList.add('hidden');
            throw err;
        }
    }

    /**
     * Seçilen RAG sonucundan ticket oluştur
     */
    async function createTicketFromSelection(query, chunkText, fileName) {
        const token = getToken();
        if (!token) {
            throw new Error('Token bulunamadı');
        }

        try {
            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            const data = await window.vyraFetch('/tickets/create-from-selection', {
                method: 'POST',
                body: {
                    query: query,
                    selected_chunk_text: chunkText,
                    selected_file_name: fileName
                }
            });
            console.log('[NGSSAI-WS] Ticket oluşturuldu:', data.id);

            return data;

        } catch (err) {
            console.error('[NGSSAI-WS] Ticket oluşturma hatası:', err);
            throw err;
        }
    }

    /**
     * Seçilen sonucu LLM (Corpix) ile değerlendir
     * @param {string} query - Kullanıcı sorgusu
     * @param {string} context - Çözüm içeriği
     * @param {number|null} ticketId - Varsa değerlendirmeyi bu ticket'a kaydeder
     */
    async function evaluateWithLLM(query, context, ticketId = null) {
        const token = getToken();
        if (!token) {
            throw new Error('Token bulunamadı');
        }

        try {
            const requestBody = {
                query: query,
                context: context
            };

            // ticket_id varsa ekle
            if (ticketId) {
                requestBody.ticket_id = ticketId;
            }

            // v3.34.0: vyraFetch — Auth + JSON + friendly error helper'da.
            const data = await window.vyraFetch('/tickets/evaluate-with-llm', {
                method: 'POST',
                body: requestBody
            });
            console.log('[NGSSAI-WS] LLM değerlendirmesi tamamlandı', ticketId ? `(Ticket #${ticketId}'e kaydedildi)` : '');

            return data;

        } catch (err) {
            console.error('[NGSSAI-WS] LLM değerlendirme hatası:', err);
            throw err;
        }
    }

    // --- INITIALIZATION ---

    function init() {
        // Sayfa yüklendiğinde bağlan
        if (getToken()) {
            connect();

            // 🔔 Browser notification izni iste (ilk seferde)
            if ('Notification' in window && Notification.permission === 'default') {
                Notification.requestPermission().then(permission => {
                    console.log('[NGSSAI-WS] Notification izni:', permission);
                });
            }
        }

        // Token değişikliklerini dinle
        window.addEventListener('storage', (e) => {
            if (e.key === 'access_token') {
                if (e.newValue) {
                    connect();
                } else {
                    disconnect();
                }
            }
        });

        // Sayfa kapanırken bağlantıyı kapat
        window.addEventListener('beforeunload', () => {
            disconnect();
        });
    }

    // --- EXPORT ---

    window.VyraWebSocket = {
        connect,
        disconnect,
        send,
        createTicketAsync,
        searchRAG,
        createTicketFromSelection,
        evaluateWithLLM,
        isConnected: () => socket && socket.readyState === WebSocket.OPEN
    };

    // Auto-init
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }

})();


/* === assets/js/modules/ui_tooltip.js === */
/* v3.33.0 — Portal tooltip helper (R011 + R012)
   ================================================
   Use cases
   ---------
   - `[data-tt]`  → CSS-only `::after` tooltip (mevcut ui_tooltip.css).
                     Container'da `overflow:hidden`/scroll yoksa tercih et.
   - `[data-tt-portal]` → JS portal tooltip (BU DOSYA).
                     Container `overflow:hidden` (table cell, modal vs.) ise
                     `::after` clipping yapar; portal `<body>`'ye render
                     edildiği için clipping olmaz + viewport auto-flip.

   API
   ---
   Otomatik bind: DOMContentLoaded'da MutationObserver kurar; dinamik olarak
   eklenen `[data-tt-portal]` elementleri otomatik tanır.

   A11y
   ----
   - Hover + focus-visible'da gösterilir.
   - aria-label fallback'i mevcut ds_enrichment_module.js MutationObserver'ı
     `data-tt` üzerinden yaptığı için, portal varyantına da `data-tt`
     attribute'u verilmesi yeterli (aria-label otomatik mirror edilir).
   - prefers-reduced-motion → fade-in animasyonu atlanır (CSS'te tanımlı).
   - Escape tuşu → açık tooltip'i kapatır.
*/

(function () {
    'use strict';

    if (window.VyraTooltipPortal && window.VyraTooltipPortal._installed) {
        return;
    }

    const PORTAL_CLASS = 'tt-portal';
    const VIEWPORT_MARGIN = 8;   // viewport kenar tampon
    const TRIGGER_GAP = 6;        // tetikleyici ile tooltip arası

    let _currentPortal = null;
    let _currentTrigger = null;

    function _escapeHtml(s) {
        return String(s)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    function _hide() {
        if (_currentPortal && _currentPortal.parentNode) {
            _currentPortal.parentNode.removeChild(_currentPortal);
        }
        _currentPortal = null;
        _currentTrigger = null;
    }

    function _show(trigger) {
        if (_currentTrigger === trigger && _currentPortal) {
            return;
        }
        _hide();

        const text = trigger.getAttribute('data-tt');
        if (!text) {
            return;
        }

        const multiline = trigger.hasAttribute('data-tt-multiline');

        const portal = document.createElement('div');
        portal.className = PORTAL_CLASS + (multiline ? ' tt-portal--multiline' : '');
        portal.setAttribute('role', 'tooltip');
        portal.innerHTML = _escapeHtml(text);
        // İlk render — measure için body'ye ekle, sonra position.
        portal.style.position = 'fixed';
        portal.style.top = '0px';
        portal.style.left = '0px';
        portal.style.visibility = 'hidden';
        document.body.appendChild(portal);

        const rect = trigger.getBoundingClientRect();
        const ttRect = portal.getBoundingClientRect();
        const vpH = window.innerHeight;
        const vpW = window.innerWidth;

        // R012 — Vertical auto-flip: tercihen tetikleyicinin ÜSTÜNDE; yoksa altına.
        let top = rect.top - ttRect.height - TRIGGER_GAP;
        if (top < VIEWPORT_MARGIN) {
            top = rect.bottom + TRIGGER_GAP;
            // Alta da sığmazsa viewport içine clamp et.
            if (top + ttRect.height > vpH - VIEWPORT_MARGIN) {
                top = Math.max(VIEWPORT_MARGIN, vpH - ttRect.height - VIEWPORT_MARGIN);
            }
        }

        // Horizontal center, viewport içine clamp.
        let left = rect.left + (rect.width / 2) - (ttRect.width / 2);
        if (left < VIEWPORT_MARGIN) left = VIEWPORT_MARGIN;
        if (left + ttRect.width > vpW - VIEWPORT_MARGIN) {
            left = vpW - ttRect.width - VIEWPORT_MARGIN;
        }

        portal.style.top = `${Math.round(top)}px`;
        portal.style.left = `${Math.round(left)}px`;
        portal.style.visibility = 'visible';

        _currentPortal = portal;
        _currentTrigger = trigger;
    }

    function _onPointerOver(e) {
        const trigger = e.target.closest('[data-tt-portal]');
        if (trigger) _show(trigger);
    }

    function _onPointerOut(e) {
        const trigger = e.target.closest('[data-tt-portal]');
        if (trigger && trigger === _currentTrigger) {
            // relatedTarget hala trigger içinde mi?
            const rel = e.relatedTarget;
            if (rel && trigger.contains(rel)) return;
            _hide();
        }
    }

    function _onFocusIn(e) {
        const trigger = e.target.closest('[data-tt-portal]');
        if (trigger) _show(trigger);
    }

    function _onFocusOut(e) {
        const trigger = e.target.closest('[data-tt-portal]');
        if (trigger && trigger === _currentTrigger) _hide();
    }

    function _onScrollOrResize() {
        if (_currentTrigger) _hide();
    }

    function _onKeyDown(e) {
        if (e.key === 'Escape' && _currentPortal) _hide();
    }

    function _install() {
        document.addEventListener('pointerover', _onPointerOver, true);
        document.addEventListener('pointerout', _onPointerOut, true);
        document.addEventListener('focusin', _onFocusIn, true);
        document.addEventListener('focusout', _onFocusOut, true);
        window.addEventListener('scroll', _onScrollOrResize, true);
        window.addEventListener('resize', _onScrollOrResize);
        document.addEventListener('keydown', _onKeyDown);
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', _install, { once: true });
    } else {
        _install();
    }

    window.VyraTooltipPortal = {
        _installed: true,
        hide: _hide,
        show: _show
    };
})();


