            + '  </div>'
            + '  <form id="' + FORM_ID + '" class="dsw-fm-body" novalidate>'
            + '    <label class="dsw-fm-field">'
            + '      <span class="dsw-fm-label">Kolon</span>'
            + '      <select id="' + COL_ID + '" required></select>'
