            var msg = 'AST yaması başarısız';
            if (status === 400) msg = 'Geçersiz işlem.';
            else if (status === 404) msg = 'Oturum bulunamadı.';
            else if (status === 409) msg = 'AST çakışması — sayfayı yenileyin.';
